// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Map;
import java.util.OptionalDouble;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost.BagEstimate;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cost.DistributionSketch;
import org.junit.jupiter.api.Test;

class CascadesEstimateVectorTest {

	@Test
	void feedbackIsIgnoredBelowConfidenceThreshold() {
		EstimateVector base = EstimateVector.heuristic(100.0d, 4.0d, "base");
		FeedbackCorrection weakFeedback = new FeedbackCorrection(10.0d, 12.0d, 0.25d, 1.5d, 1.5d,
				"weak-feedback");

		EstimateVector adjusted = base.applyFeedback(weakFeedback, 0.55d);

		assertEquals(base, adjusted);
	}

	@Test
	void trustedFeedbackCarriesRowsWorkAndQErrorIntoTheVector() {
		EstimateVector base = EstimateVector.heuristic(100.0d, 8.0d, "base");
		FeedbackCorrection feedback = new FeedbackCorrection(20.0d, 25.0d, 0.90d, 2.0d, 3.0d,
				"operator-feedback");

		EstimateVector adjusted = base.applyFeedback(feedback, 0.55d);

		assertEquals(20.0d, adjusted.rows());
		assertEquals(25.0d, adjusted.workRows());
		assertEquals(2.0d, adjusted.rowQErrorMean());
		assertEquals(3.0d, adjusted.rowQErrorMax());
		assertEquals(3.0d, adjusted.workQErrorMean());
		assertEquals(3.0d, adjusted.workQErrorMax());
		assertEquals(0.90d, adjusted.confidence());
		assertTrue(adjusted.metrics().containsKey("plannedFeedbackConfidence"));
	}

	@Test
	void robustObjectivePenalizesLowConfidenceHighQErrorPlans() {
		CostVector confident = new CostVector(100.0d, 100.0d, 0.0d, 0.0d, 0.0d, 1.2d, 1.2d,
				1.2d, 1.2d, 10.0d, 0.95d, 8.0d);
		CostVector uncertain = new CostVector(100.0d, 100.0d, 0.0d, 0.0d, 0.0d, 10.0d, 20.0d,
				10.0d, 20.0d, 500.0d, 0.05d, 0.0d);

		assertTrue(confident.compareTo(uncertain) < 0);
		assertTrue(uncertain.objectiveScore() > confident.objectiveScore());
	}

	@Test
	void filterKeepsQErrorIntervalInsteadOfCollapsingToScalarRows() {
		EstimateVector base = EstimateVector.heuristic(1_000.0d, 5.0d, "base");
		QErrorInterval passInterval = QErrorInterval.fromBounds(0.10d, 0.25d, 0.50d, 0.70d,
				"learned-filter");

		EstimateVector filtered = base.filter(0.25d, passInterval, "filter");

		assertEquals(250.0d, filtered.rows());
		assertTrue(filtered.lowerRows() < filtered.rows());
		assertTrue(filtered.upperRows() > filtered.rows());
		assertEquals(0.70d, filtered.confidence());
	}

	@Test
	void vectorRoundTripPreservesRobustDimensions() {
		EstimateVector vector = new EstimateVector(20.0d, 10.0d, 80.0d, 30.0d, 2.0d, 3.0d, 5.0d,
				2.0d, 8.0d, 3.0d, 9.0d, 70.0d, 0.60d, 4.0d, "source", Map.of());

		EstimateVector roundTripped = StatisticsEstimate.fromVector(vector, "round-trip").vector();

		assertEquals(8.0d, roundTripped.rowQErrorMax());
		assertEquals(9.0d, roundTripped.workQErrorMax());
		assertEquals(70.0d, roundTripped.uncertaintyRows());
		assertEquals(0.60d, roundTripped.confidence());
		assertEquals(4.0d, roundTripped.evidenceCount());
		assertEquals(5.0d, roundTripped.pageWalkRows());
	}

	@Test
	void fromBagCountsSketchRelationsAsEvidence() {
		BagEstimate bag = BagEstimate.heuristic(20.0d, "sketch-bag")
				.withSketchRelation(Set.of("x"), new TestSketch(10.0d, 20.0d));

		EstimateVector vector = StatisticsEstimate.fromBag(bag, "sketch-provider").vector();

		assertEquals(1.0d, vector.evidenceCount());
		assertEquals(1.0d, vector.metrics().get("optimizer.vectorEvidenceCount"));
	}

	private record TestSketch(double distinctRows, double innerProduct) implements DistributionSketch {

		@Override
		public OptionalDouble innerProduct(DistributionSketch other) {
			return OptionalDouble.of(innerProduct);
		}

		@Override
		public OptionalDouble highQualityInnerProduct(DistributionSketch other) {
			return OptionalDouble.of(innerProduct);
		}
	}
}
